<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        
        <template v-if="NoteList.length > 0">
            <div class="pb-2" id="div_NotesLabel">
                                        <span class="legend-Progress colorboxsquare"></span>{{ $t('Private') }}
                                        <span class="legend-upcoming colorboxsquare ml-3"></span>{{ $t('Public') }}
                                    </div>
            <div class="row card-view no-bg custom-box-width">

                <div class="col-md-12 col-lg-6 col-xl-3 mb-3" v-for="(note, index) in NoteList" :key="index">
                    <div
                        :class="{ 'card-box': true, 'green-bg-light': note.PRIVACY != 'Public', 'blue-bg-light': note.PRIVACY == 'Public' }">
                        <div class="card-heading">
                            <span class="user-img-con mr-2">
                                <img v-if="note.AVATAR" class="img-circle avatar" :src="note.AVATAR"
                                    :alt="$t('Image')" />
                                <img v-else class="img-circle avatar"
                                    src="/Content/images/DefaultImages/avatar-icon.jpg" :alt="$t('Image')" border="0" />
                            </span>
                            {{ !note.DEPARTMENT_NAME ? '--' : note.DEPARTMENT_NAME }}
                        </div>
                        <div class="card-detail-main1 dynamiclistol">
                            <div class="card-detail"><em class="fa fa-user" aria-hidden="true"></em>
                                <span>{{ note.CREATED_BY_NAME }}</span>
                            </div>
                            <hr class="my-2" />
                            <div class="clearfix"></div>
                            <div class="commentnoteslist" style="max-height: 150px; overflow-y: auto;">
                                <div class="w-100 float-left custom-scrollbar-js" v-html="note.NOTE"></div>
                            </div>
                        </div>
                        <div class="bottom-action">
                            <div class="card-date">
                                <em class="fa fa-calendar-o" aria-hidden="true"></em>
                                <span>
                                    {{ !note.CREATED_AT ? '--' : $options.filters.formatDateTime(note.CREATED_AT) }}
                                </span>
                            </div>
                            <div class="card-action">
                                <span v-on:click="DownloadAttachment(NoteList, note.NOTE_ID)">
                                    <a v-if="AttachmentsData.length > 0"
                                        class="round-icon-small btn-primary-light downloadAttachement"
                                        :title="$t('ClickHereDownloadAttachment')" :alt="$t('DownloadFile')"
                                        href="javascript:;">
                                        <em class="fa fa-download"></em>
                                    </a>
                                </span>
                                <a v-if="ListNoteData != 1" v-on:click="EditNote(note)"
                                    class="round-icon-small btn-success-light" :title="$t('EditNotes')"
                                    :alt="$t('EditNotes')" href="javascript:;">
                                    <em class="fa fa-edit"></em>
                                </a>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </template>
        <div class="col-sm-12 col-md-12 col-lg-12 mt-2" v-if="NoRecords">
            <span class="text-danger text-center d-block no-record">{{ $t('NoRecordfound') }}</span>
        </div>
    </section>
</template>


<script>
import DataServices from "@/services/DataService";
export default {
    props: {
        NoteData: {
            type: Array,
            required: true
        },
        ListNoteData: {
            type: Number,
            required: false
        }
    },
    data() {
        return {
            NoRecords: false,
            isShowAddNote: false,
            UserId: null,
            NoteList: [],
            isLoading: false,
            noteId: 0,
            noteDataById: [],
            AttachmentsData: []
        }
    },
    watch: {
        NoteData: function (val) {
            var vm = this;
            vm.NoteList = val;
            if (vm.NoteList.length > 0) {
                vm.NoRecords = false;
            }
            else {
                vm.NoteList = [];
                vm.NoRecords = true;
            }
        }
    },
    created() {
        setTimeout(() => {
            var vm = this;
            vm.UserId = vm.GetUserInfo.ID;
            vm.ListNoteData = this.ListNoteData;
            if (!vm.isBlank(vm.NoteData)) {
                vm.NoteList = vm.NoteData;
                vm.NoteList.forEach(itm => {
                    if (itm.ATTACHMENTS_JSON ) {
                        vm.AttachmentsData = JSON.parse(itm.ATTACHMENTS_JSON);
                    }
                });
                vm.NoRecords = false;
            }
            else {
                vm.NoRecords = true;
                vm.NoteList = [];
            }
        }, 500);
    },
    methods: {
        EditNote: function (item) {
            var vm = this;
            var param = 'controller=Ticketing&action=EditNote';
            DataServices.CheckPrivilege(param).then(function (response) {
                if (response.data) {
                    vm.$parent.noteId = item.NOTE_ID;
                    vm.$parent.ticketId = item.TICKET_ID;
                    vm.$parent.note = item.NOTE;
                    vm.$parent.privacy = item.PRIVACY;
                    vm.$parent.ATTACHMENT_NAME = item.ATTACHMENT_NAME;
                    vm.$parent.ATTACHMENT_PATH = item.ATTACHMENT_PATH;
                    vm.$parent.isShowAddNote = true;
                }
                else
                {
                    vm.ShowAlert(vm.$t('NotAuthorizedSection'), "warning", true, vm.$t("Alert"));
                }
            });
        },
        DownloadAttachment(items, clickedNoteId) {
            var vm = this;
            vm.isLoading = true;
            var validAttachments = [];
            items.forEach((itm) => {
                if(itm.NOTE_ID == clickedNoteId) {
                    validAttachments = JSON.parse(itm.ATTACHMENTS_JSON);
                }
            });
            validAttachments.forEach(element => {
                var param = `filePath=${element.ATTACHMENT_PATH}&fileName=${element.ATTACHMENT_NAME}`;
                DataServices.DownloadFile(param).then(function (response) {
                    var byteData = response.data;
                    var contentType = JSON.parse(element.ATTACHMENT_DESC)?.ContentType || 'application/octet-stream';
                    var fileURL = `data:${contentType};base64,${byteData}`;
                    var fileLink = document.createElement('a');
                    fileLink.href = fileURL;
                    fileLink.setAttribute('download', element.ATTACHMENT_NAME);
                    document.body.appendChild(fileLink);
                    fileLink.click();
                    document.body.removeChild(fileLink); 
                }).catch(error => {
                    console.error(`Error downloading ${element.ATTACHMENT_NAME}:`, error);
                });
            });
            vm.isLoading = false;
        }
    }
}
</script>